import React, { useState } from 'react';
import { Product } from '../types/index';
import ProductCard from '../components/ProductCard';
import { faFacebook, faInstagram, faYoutube, faBlogger, faTwitter, faTelegram, IconDefinition } from '@fortawesome/free-brands-svg-icons';

const categoryIcon: Record<string, { icon: IconDefinition; color: string }> = {
  '페이스북': { icon: faFacebook, color: 'text-blue-600' },
  '인스타그램': { icon: faInstagram, color: 'text-pink-500' },
  '유튜브': { icon: faYoutube, color: 'text-red-600' },
  '블로그': { icon: faBlogger, color: 'text-orange-500' },
  '트위터': { icon: faTwitter, color: 'text-sky-400' },
  '텔레그램': { icon: faTelegram, color: 'text-blue-400' },
  '기타': { icon: faBlogger, color: 'text-gray-400' },
};

const Favorits: React.FC = () => {
  const [favorites, setFavorites] = useState<Product[]>([
    {
      id: 1,
      name: '페이스북 팔로워 1000명',
      price: '50,000원',
      category: '페이스북',
      image: 'https://via.placeholder.com/200x150?text=Facebook',
      addedDate: '2024-01-15'
    },
    {
      id: 2,
      name: '인스타그램 팔로워 500명',
      price: '30,000원',
      category: '인스타그램',
      image: 'https://via.placeholder.com/200x150?text=Instagram',
      addedDate: '2024-01-10'
    },
    {
      id: 3,
      name: '유튜브 구독자 1000명',
      price: '100,000원',
      category: '유튜브',
      image: 'https://via.placeholder.com/200x150?text=YouTube',
      addedDate: '2024-01-08'
    },
    {
      id: 4,
      name: '블로그 방문자 5000명',
      price: '80,000원',
      category: '블로그',
      image: 'https://via.placeholder.com/200x150?text=Blog',
      addedDate: '2024-01-05'
    }
  ]);

  const handleRemoveFavorite = (id: number): void => {
    setFavorites(prev => prev.filter(product => product.id !== id));
    alert('즐겨찾기에서 제거되었습니다.');
  };

  const handleRemoveAllFavorites = (): void => {
    if (window.confirm('모든 즐겨찾기를 삭제하시겠습니까?')) {
      setFavorites([]);
      alert('모든 즐겨찾기가 삭제되었습니다.');
    }
  };

  const toggleFavorite = (id: number) => {
    handleRemoveFavorite(id);
  };

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        {/* Page Header */}
        <div className="mb-8">
          <h1 className="text-3xl font-bold text-gray-900 mb-4">즐겨찾기</h1>
          <p className="text-gray-600">즐겨찾기한 상품을 관리하세요</p>
        </div>

        <div className="bg-white rounded-lg shadow-md overflow-hidden">
          <div className="border-b border-gray-200">
            <nav className="flex">
              <button
                className={`px-6 py-4 text-sm font-medium border-b-2 border-blue-600 text-blue-600`}
                disabled
              >
                즐겨찾기
              </button>
            </nav>
          </div>

          <div className="p-6">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-lg font-semibold text-gray-900">즐겨찾기</h3>
              {favorites.length > 0 && (
                <button
                  onClick={handleRemoveAllFavorites}
                  className="text-red-600 hover:text-red-700 text-sm font-medium"
                >
                  전체 삭제
                </button>
              )}
            </div>

            {favorites.length === 0 ? (
              <div className="text-center py-12">
                <div className="text-gray-400 mb-4">
                  <svg className="mx-auto h-12 w-12" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z" />
                  </svg>
                </div>
                <p className="text-gray-500 text-lg">즐겨찾기한 상품이 없습니다.</p>
                <p className="text-gray-400 text-sm mt-2">상품을 즐겨찾기에 추가해보세요.</p>
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                {favorites.map((product) => (
                  <ProductCard
                    key={product.id}
                    product={product}
                    isFavorite={true}
                    onFavoriteToggle={toggleFavorite}
                    categoryIcon={categoryIcon[product.category] || categoryIcon['기타']}
                  />
                ))}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Favorits;
